```class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        string str1 = "";
        for (int i = 0; i < n1; i++) {
            str1 += s1;
        }
        int count = 0;
        for (int i = 0; i < str1.size(); i++) {
            int j = 0;
            while (i < str1.size() && j < s2.size()) {
                if (str1[i] == s2[j]) {
                    i++;
                    j++;
                } else {
                    i++;
                }
            }
            if (j == s2.size()) {
                count++;
            }
        }
        return count / n2;
    }
};
```
